#include <iostream>
#include <limits>

using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;

    int min_val = numeric_limits<int>::max();
    int count = 0;

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            int x;
            cin >> x;
            if (x < min_val) {
                min_val = x;
                count = 1;
            } else if (x == min_val) {
                ++count;
            }
        }
    }

    cout << min_val << " " << count << "\n";

    return 0;
}
